const body = $input.first().json.body || $input.first().json;
const required = ['clientName', 'amountBeforeVat', 'serviceDescription', 'paymentMethod'];
const missing = required.filter(k => !body[k]);
if (missing.length) throw new Error('Missing required fields: ' + missing.join(', '));

const amountBeforeVat = Number(body.amountBeforeVat);
const vatRate = 0.17;
const vatAmount = Math.round(amountBeforeVat * vatRate);
const totalAmount = amountBeforeVat + vatAmount;

const receiptDate = new Date().toLocaleDateString('he-IL');

return [{ json: {
  clientName: body.clientName,
  clientId: body.clientId || '',
  serviceDescription: body.serviceDescription || 'ייעוץ משכנתאות',
  amountBeforeVat,
  vatAmount,
  totalAmount,
  paymentMethod: body.paymentMethod,
  notes: body.notes || '',
  caseId: body.caseId || '',
  clientEmail: body.clientEmail || '',
  receiptDate,
  receiptNumber: body.receiptNumber || `R-${Date.now()}`
}}];

const d = $input.first().json;
const PAYMENT_LABELS = { 'bank-transfer': 'העברה בנקאית', 'cash': 'מזומן', 'credit-card': 'כרטיס אשראי' };
const html = `<!DOCTYPE html>
<html dir="rtl" lang="he">
<head><meta charset="UTF-8"><style>
body { font-family: Arial, sans-serif; direction: rtl; padding: 40px; max-width: 700px; margin: 0 auto; color: #222; }
h1 { font-size: 22px; margin-bottom: 4px; }
.subtitle { color: #666; font-size: 14px; margin-bottom: 30px; }
.meta { border: 1px solid #ddd; border-radius: 8px; padding: 20px; margin-bottom: 24px; }
.row { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid #f0f0f0; font-size: 14px; }
.row:last-child { border-bottom: none; }
.total-row { font-weight: bold; font-size: 16px; color: #0066cc; padding-top: 12px; }
.footer { margin-top: 40px; font-size: 12px; color: #888; text-align: center; }
</style></head>
<body>
<h1>חשבונית מס קבלה</h1>
<p class="subtitle">מספר: ${d.receiptNumber} · תאריך: ${d.receiptDate}</p>
<div class="meta">
  <div class="row"><span>שם לקוח</span><strong>${d.clientName}</strong></div>
  ${d.clientId ? `<div class="row"><span>ת.ז.</span><span>${d.clientId}</span></div>` : ''}
  ${d.caseId ? `<div class="row"><span>מספר תיק</span><span>${d.caseId}</span></div>` : ''}
  <div class="row"><span>תיאור שירות</span><span>${d.serviceDescription}</span></div>
  <div class="row"><span>אמצעי תשלום</span><span>${PAYMENT_LABELS[d.paymentMethod] || d.paymentMethod}</span></div>
</div>
<div class="meta">
  <div class="row"><span>סכום לפני מע"מ</span><span>₪${d.amountBeforeVat.toLocaleString('he-IL')}</span></div>
  <div class="row"><span>מע"מ (17%)</span><span>₪${d.vatAmount.toLocaleString('he-IL')}</span></div>
  <div class="row total-row"><span>סה"כ לתשלום</span><span>₪${d.totalAmount.toLocaleString('he-IL')}</span></div>
</div>
${d.notes ? `<p style="font-size:13px;color:#555">הערות: ${d.notes}</p>` : ''}
<div class="footer">מסמך זה הופק אוטומטית על ידי מערכת KeyPoint</div>
</body></html>`;
return [{ json: { ...d, html } }];
